"use client";

import React, { useEffect, useRef, useState, useCallback } from "react";
import { cn } from "@/lib/utils";

interface WaterRippleProps {
  /** Image source URL */
  src: string;
  /** Size of the ripple brush in px */
  brushSize?: number;
  /** Ripple intensity (0-1) */
  intensity?: number;
  /** Ripple decay speed (0-1, higher = faster fade) */
  decay?: number;
  className?: string;
  children?: React.ReactNode;
}

// ── Brush texture generator (circular gradient) ─────────────────────────────
function createBrushTexture(gl: WebGLRenderingContext, size: number): WebGLTexture {
  const canvas = document.createElement("canvas");
  canvas.width = size;
  canvas.height = size;
  const ctx = canvas.getContext("2d")!;

  const gradient = ctx.createRadialGradient(
    size / 2, size / 2, 0,
    size / 2, size / 2, size / 2
  );
  gradient.addColorStop(0, "rgba(255, 255, 255, 1)");
  gradient.addColorStop(0.5, "rgba(255, 255, 255, 0.5)");
  gradient.addColorStop(1, "rgba(255, 255, 255, 0)");

  ctx.fillStyle = gradient;
  ctx.fillRect(0, 0, size, size);

  const texture = gl.createTexture()!;
  gl.bindTexture(gl.TEXTURE_2D, texture);
  gl.texImage2D(gl.TEXTURE_2D, 0, gl.RGBA, gl.RGBA, gl.UNSIGNED_BYTE, canvas);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MAG_FILTER, gl.LINEAR);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_S, gl.CLAMP_TO_EDGE);
  gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_WRAP_T, gl.CLAMP_TO_EDGE);

  return texture;
}

// ── Shader sources ──────────────────────────────────────────────────────────
const QUAD_VS = `
  attribute vec2 a_position;
  varying vec2 v_uv;
  void main() {
    v_uv = a_position * 0.5 + 0.5;
    gl_Position = vec4(a_position, 0.0, 1.0);
  }
`;

const RIPPLE_VS = `
  attribute vec2 a_position;
  uniform vec2 u_point;
  uniform float u_size;
  uniform vec2 u_resolution;
  varying vec2 v_uv;
  void main() {
    v_uv = a_position * 0.5 + 0.5;
    vec2 pos = u_point + a_position * u_size;
    vec2 ndc = (pos / u_resolution) * 2.0 - 1.0;
    ndc.y = -ndc.y;
    gl_Position = vec4(ndc, 0.0, 1.0);
  }
`;

const RIPPLE_FS = `
  precision highp float;
  uniform sampler2D u_brush;
  uniform float u_opacity;
  uniform float u_rotation;
  varying vec2 v_uv;
  void main() {
    vec2 center = v_uv - 0.5;
    float s = sin(u_rotation);
    float c = cos(u_rotation);
    vec2 rotated = vec2(c * center.x - s * center.y, s * center.x + c * center.y) + 0.5;
    vec4 brush = texture2D(u_brush, rotated);
    gl_FragColor = vec4(brush.rgb, brush.a * u_opacity);
  }
`;

const OUTPUT_FS = `
  precision highp float;
  uniform sampler2D u_image;
  uniform sampler2D u_displacement;
  uniform vec2 u_resolution;
  uniform vec2 u_imageSize;
  uniform float u_intensity;
  varying vec2 v_uv;

  #define PI 3.141592653589793

  vec2 coverUV(vec2 uv, vec2 texSize) {
    vec2 s = u_resolution / texSize;
    float scale = max(s.x, s.y);
    vec2 scaled = texSize * scale;
    vec2 offset = (u_resolution - scaled) * 0.5;
    return (uv * u_resolution - offset) / scaled;
  }

  void main() {
    vec2 cuv = coverUV(v_uv, u_imageSize);
    vec4 disp = texture2D(u_displacement, v_uv);
    float theta = disp.r * 2.0 * PI;
    vec2 dir = vec2(sin(theta), cos(theta));
    vec2 finalUv = cuv + dir * disp.r * 0.05 * u_intensity;
    gl_FragColor = texture2D(u_image, finalUv);
  }
`;

// ── Ripple wave state ───────────────────────────────────────────────────────
interface Wave {
  x: number;
  y: number;
  opacity: number;
  scale: number;
  rotation: number;
  active: boolean;
}

// ── Component ───────────────────────────────────────────────────────────────
export function WaterRipple({
  src,
  brushSize = 100,
  intensity = 1,
  decay = 0.96,
  className,
  children,
}: WaterRippleProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [mounted, setMounted] = useState(false);

  useEffect(() => { setMounted(true); }, []);

  useEffect(() => {
    if (!mounted || !canvasRef.current) return;

    const canvas = canvasRef.current;
    const gl = canvas.getContext("webgl", {
      alpha: false,
      premultipliedAlpha: false,
      antialias: false,
    });
    if (!gl) return;

    let raf: number;
    let destroyed = false;

    // ── Helpers ──────────────────────────────────────────────
    function createShader(type: number, source: string): WebGLShader {
      const shader = gl!.createShader(type)!;
      gl!.shaderSource(shader, source);
      gl!.compileShader(shader);
      return shader;
    }

    function createProgram(vs: string, fs: string): WebGLProgram {
      const program = gl!.createProgram()!;
      gl!.attachShader(program, createShader(gl!.VERTEX_SHADER, vs));
      gl!.attachShader(program, createShader(gl!.FRAGMENT_SHADER, fs));
      gl!.linkProgram(program);
      return program;
    }

    function createFBO(w: number, h: number) {
      const tex = gl!.createTexture()!;
      gl!.bindTexture(gl!.TEXTURE_2D, tex);
      gl!.texImage2D(gl!.TEXTURE_2D, 0, gl!.RGBA, w, h, 0, gl!.RGBA, gl!.UNSIGNED_BYTE, null);
      gl!.texParameteri(gl!.TEXTURE_2D, gl!.TEXTURE_MIN_FILTER, gl!.LINEAR);
      gl!.texParameteri(gl!.TEXTURE_2D, gl!.TEXTURE_MAG_FILTER, gl!.LINEAR);
      gl!.texParameteri(gl!.TEXTURE_2D, gl!.TEXTURE_WRAP_S, gl!.CLAMP_TO_EDGE);
      gl!.texParameteri(gl!.TEXTURE_2D, gl!.TEXTURE_WRAP_T, gl!.CLAMP_TO_EDGE);
      const fbo = gl!.createFramebuffer()!;
      gl!.bindFramebuffer(gl!.FRAMEBUFFER, fbo);
      gl!.framebufferTexture2D(gl!.FRAMEBUFFER, gl!.COLOR_ATTACHMENT0, gl!.TEXTURE_2D, tex, 0);
      gl!.bindFramebuffer(gl!.FRAMEBUFFER, null);
      return { fbo, texture: tex };
    }

    // ── Setup ────────────────────────────────────────────────
    const container = canvas.parentElement!;
    let W = container.clientWidth;
    let H = container.clientHeight;
    const dpr = Math.min(window.devicePixelRatio, 2);

    function resize() {
      W = container.clientWidth;
      H = container.clientHeight;
      canvas.width = W * dpr;
      canvas.height = H * dpr;
      canvas.style.width = W + "px";
      canvas.style.height = H + "px";
      gl!.viewport(0, 0, canvas.width, canvas.height);
      // Recreate FBO at new size
      rippleFBO = createFBO(canvas.width, canvas.height);
    }

    // Quad buffer
    const quadBuf = gl.createBuffer()!;
    gl.bindBuffer(gl.ARRAY_BUFFER, quadBuf);
    gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1,-1, 1,-1, -1,1, 1,1]), gl.STATIC_DRAW);

    // Brush texture
    const brushTex = createBrushTexture(gl, 128);

    // FBO for ripple accumulation
    let rippleFBO = createFBO(W * dpr, H * dpr);

    // Ripple program
    const rippleProg = createProgram(RIPPLE_VS, RIPPLE_FS);
    const rp_pos = gl.getAttribLocation(rippleProg, "a_position");
    const rp_point = gl.getUniformLocation(rippleProg, "u_point");
    const rp_size = gl.getUniformLocation(rippleProg, "u_size");
    const rp_res = gl.getUniformLocation(rippleProg, "u_resolution");
    const rp_brush = gl.getUniformLocation(rippleProg, "u_brush");
    const rp_opacity = gl.getUniformLocation(rippleProg, "u_opacity");
    const rp_rotation = gl.getUniformLocation(rippleProg, "u_rotation");

    // Output program
    const outputProg = createProgram(QUAD_VS, OUTPUT_FS);
    const op_pos = gl.getAttribLocation(outputProg, "a_position");
    const op_image = gl.getUniformLocation(outputProg, "u_image");
    const op_disp = gl.getUniformLocation(outputProg, "u_displacement");
    const op_res = gl.getUniformLocation(outputProg, "u_resolution");
    const op_imgSize = gl.getUniformLocation(outputProg, "u_imageSize");
    const op_intensity = gl.getUniformLocation(outputProg, "u_intensity");

    // Load image as texture
    let imageTex: WebGLTexture | null = null;
    let imgW = 1, imgH = 1;
    const img = new window.Image();
    img.crossOrigin = "anonymous";
    img.onload = () => {
      if (destroyed) return;
      imgW = img.naturalWidth;
      imgH = img.naturalHeight;
      imageTex = gl!.createTexture()!;
      gl!.bindTexture(gl!.TEXTURE_2D, imageTex);
      gl!.texImage2D(gl!.TEXTURE_2D, 0, gl!.RGBA, gl!.RGBA, gl!.UNSIGNED_BYTE, img);
      gl!.texParameteri(gl!.TEXTURE_2D, gl!.TEXTURE_MIN_FILTER, gl!.LINEAR);
      gl!.texParameteri(gl!.TEXTURE_2D, gl!.TEXTURE_MAG_FILTER, gl!.LINEAR);
      gl!.texParameteri(gl!.TEXTURE_2D, gl!.TEXTURE_WRAP_S, gl!.CLAMP_TO_EDGE);
      gl!.texParameteri(gl!.TEXTURE_2D, gl!.TEXTURE_WRAP_T, gl!.CLAMP_TO_EDGE);
    };
    img.src = src;

    // Waves
    const MAX_WAVES = 80;
    const waves: Wave[] = Array.from({ length: MAX_WAVES }, () => ({
      x: 0, y: 0, opacity: 0, scale: 1, rotation: 0, active: false,
    }));
    let currentWave = 0;
    let prevX = -999, prevY = -999;

    const onPointerMove = (e: PointerEvent) => {
      const rect = canvas.getBoundingClientRect();
      const x = (e.clientX - rect.left) * dpr;
      const y = (e.clientY - rect.top) * dpr;

      if (Math.abs(x - prevX) > 3 * dpr || Math.abs(y - prevY) > 3 * dpr) {
        const wave = waves[currentWave];
        wave.x = x;
        wave.y = y;
        wave.opacity = 1;
        wave.scale = 1;
        wave.rotation = Math.random() * Math.PI * 2;
        wave.active = true;
        currentWave = (currentWave + 1) % MAX_WAVES;
        prevX = x;
        prevY = y;
      }
    };

    canvas.addEventListener("pointermove", onPointerMove);
    resize();
    window.addEventListener("resize", resize);

    // ── Render loop ─────────────────────────────────────────
    function render() {
      if (destroyed) return;
      raf = requestAnimationFrame(render);

      const cw = canvas.width;
      const ch = canvas.height;

      // Pass 1: Render ripple waves into FBO
      gl!.bindFramebuffer(gl!.FRAMEBUFFER, rippleFBO.fbo);
      gl!.viewport(0, 0, cw, ch);
      // Don't clear — accumulate with blend, but fade previous
      gl!.enable(gl!.BLEND);
      gl!.blendFunc(gl!.SRC_ALPHA, gl!.ONE_MINUS_SRC_ALPHA);

      // Fade previous frame by drawing a dim black quad
      // Actually, we clear with slight alpha to fade
      gl!.clearColor(0, 0, 0, 1);
      gl!.clear(gl!.COLOR_BUFFER_BIT);

      gl!.useProgram(rippleProg);
      gl!.bindBuffer(gl!.ARRAY_BUFFER, quadBuf);
      gl!.enableVertexAttribArray(rp_pos);
      gl!.vertexAttribPointer(rp_pos, 2, gl!.FLOAT, false, 0, 0);

      gl!.activeTexture(gl!.TEXTURE0);
      gl!.bindTexture(gl!.TEXTURE_2D, brushTex);
      gl!.uniform1i(rp_brush, 0);
      gl!.uniform2f(rp_res, cw, ch);

      // Draw active waves
      for (const wave of waves) {
        if (!wave.active) continue;

        wave.opacity *= decay;
        wave.scale += 0.02;
        wave.rotation += 0.02;

        if (wave.opacity < 0.002) {
          wave.active = false;
          continue;
        }

        const sz = brushSize * dpr * wave.scale * 0.5;
        gl!.uniform2f(rp_point, wave.x, wave.y);
        gl!.uniform1f(rp_size, sz);
        gl!.uniform1f(rp_opacity, wave.opacity);
        gl!.uniform1f(rp_rotation, wave.rotation);
        gl!.drawArrays(gl!.TRIANGLE_STRIP, 0, 4);
      }

      gl!.disable(gl!.BLEND);

      // Pass 2: Render output with displacement
      gl!.bindFramebuffer(gl!.FRAMEBUFFER, null);
      gl!.viewport(0, 0, cw, ch);
      gl!.clearColor(0, 0, 0, 1);
      gl!.clear(gl!.COLOR_BUFFER_BIT);

      if (!imageTex) return;

      gl!.useProgram(outputProg);
      gl!.bindBuffer(gl!.ARRAY_BUFFER, quadBuf);
      gl!.enableVertexAttribArray(op_pos);
      gl!.vertexAttribPointer(op_pos, 2, gl!.FLOAT, false, 0, 0);

      gl!.activeTexture(gl!.TEXTURE0);
      gl!.bindTexture(gl!.TEXTURE_2D, imageTex);
      gl!.uniform1i(op_image, 0);

      gl!.activeTexture(gl!.TEXTURE1);
      gl!.bindTexture(gl!.TEXTURE_2D, rippleFBO.texture);
      gl!.uniform1i(op_disp, 1);

      gl!.uniform2f(op_res, cw, ch);
      gl!.uniform2f(op_imgSize, imgW, imgH);
      gl!.uniform1f(op_intensity, intensity);

      gl!.drawArrays(gl!.TRIANGLE_STRIP, 0, 4);
    }

    raf = requestAnimationFrame(render);

    return () => {
      destroyed = true;
      cancelAnimationFrame(raf);
      window.removeEventListener("resize", resize);
      canvas.removeEventListener("pointermove", onPointerMove);
    };
  }, [mounted, src, brushSize, intensity, decay]);

  if (!mounted) {
    return <div className={cn("relative w-full h-full min-h-[400px] bg-black", className)} />;
  }

  return (
    <div className={cn("relative w-full h-full min-h-[400px] overflow-hidden", className)}>
      <canvas
        ref={canvasRef}
        className="absolute inset-0 h-full w-full"
        style={{ touchAction: "none" }}
      />
      {children && (
        <div className="relative z-10 flex h-full items-center justify-center">
          {children}
        </div>
      )}
    </div>
  );
}
